import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader
import torchvision.models as models
import torchvision.transforms as transforms
from PIL import Image
import requests
import os
from pathlib import Path
import hashlib
from typing import Optional, Callable, Tuple
import json


class ModelDownloader:
    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        
    def download_checkpoint(self, url: str, filename: Optional[str] = None) -> str:
        if filename is None:
            filename = hashlib.md5(url.encode()).hexdigest() + ".pth"
        
        filepath = self.cache_dir / filename
        
        if filepath.exists():
            print(f"Checkpoint already cached at {filepath}")
            return str(filepath)
        
        print(f"Downloading checkpoint from {url}...")
        response = requests.get(url, stream=True)
        response.raise_for_status()
        
        total_size = int(response.headers.get('content-length', 0))
        downloaded = 0
        
        with open(filepath, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                if chunk:
                    f.write(chunk)
                    downloaded += len(chunk)
                    if total_size > 0:
                        progress = (downloaded / total_size) * 100
                        print(f"\rProgress: {progress:.1f}%", end='')
        
        print(f"\nCheckpoint saved to {filepath}")
        return str(filepath)
    
    def load_checkpoint(self, path_or_url: str, map_location: str = 'cpu') -> dict:
        if path_or_url.startswith('http://') or path_or_url.startswith('https://'):
            local_path = self.download_checkpoint(path_or_url)
        else:
            local_path = path_or_url
        
        print(f"Loading checkpoint from {local_path}...")
        checkpoint = torch.load(local_path, map_location=map_location)
        return checkpoint


class CustomDataset(Dataset):
    def __init__(self, data_list, labels, transform=None):
        self.data = data_list
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        data = self.data[idx]
        label = self.labels[idx]
        
        if isinstance(data, str):
            data = Image.open(data).convert('RGB')
        
        if self.transform:
            data = self.transform(data)
        
        return data, label


class TransferLearningPipeline:
    def __init__(self, num_classes: int, device: str = 'cuda' if torch.cuda.is_available() else 'cpu'):
        self.num_classes = num_classes
        self.device = device
        self.model = None
        self.downloader = ModelDownloader()
        
    def load_pretrained_model(self, model_name: str = 'resnet50', checkpoint_url: Optional[str] = None):
        if checkpoint_url:
            checkpoint = self.downloader.load_checkpoint(checkpoint_url, map_location=self.device)
            
            if model_name == 'resnet50':
                self.model = models.resnet50(pretrained=False)
            elif model_name == 'resnet18':
                self.model = models.resnet18(pretrained=False)
            elif model_name == 'vgg16':
                self.model = models.vgg16(pretrained=False)
            elif model_name == 'efficientnet_b0':
                self.model = models.efficientnet_b0(pretrained=False)
            else:
                raise ValueError(f"Unsupported model: {model_name}")
            
            if 'state_dict' in checkpoint:
                self.model.load_state_dict(checkpoint['state_dict'], strict=False)
            elif 'model' in checkpoint:
                self.model.load_state_dict(checkpoint['model'], strict=False)
            else:
                self.model.load_state_dict(checkpoint, strict=False)
            
            print(f"Loaded checkpoint from {checkpoint_url}")
        else:
            if model_name == 'resnet50':
                self.model = models.resnet50(pretrained=True)
            elif model_name == 'resnet18':
                self.model = models.resnet18(pretrained=True)
            elif model_name == 'vgg16':
                self.model = models.vgg16(pretrained=True)
            elif model_name == 'efficientnet_b0':
                self.model = models.efficientnet_b0(pretrained=True)
            else:
                raise ValueError(f"Unsupported model: {model_name}")
            
            print(f"Loaded pretrained {model_name} from torchvision")
        
        self._modify_classifier(model_name)
        self.model = self.model.to(self.device)
        
    def _modify_classifier(self, model_name: str):
        if 'resnet' in model_name:
            num_features = self.model.fc.in_features
            self.model.fc = nn.Linear(num_features, self.num_classes)
        elif 'vgg' in model_name:
            num_features = self.model.classifier[6].in_features
            self.model.classifier[6] = nn.Linear(num_features, self.num_classes)
        elif 'efficientnet' in model_name:
            num_features = self.model.classifier[1].in_features
            self.model.classifier[1] = nn.Linear(num_features, self.num_classes)
    
    def freeze_backbone(self, freeze: bool = True):
        for name, param in self.model.named_parameters():
            if 'fc' not in name and 'classifier' not in name:
                param.requires_grad = not freeze
        
        print(f"Backbone {'frozen' if freeze else 'unfrozen'}")
    
    def fine_tune(
        self,
        train_loader: DataLoader,
        val_loader: Optional[DataLoader] = None,
        epochs: int = 10,
        learning_rate: float = 0.001,
        optimizer_type: str = 'adam',
        save_path: str = 'finetuned_model.pth',
        freeze_backbone: bool = True
    ):
        if freeze_backbone:
            self.freeze_backbone(True)
        
        criterion = nn.CrossEntropyLoss()
        
        if optimizer_type.lower() == 'adam':
            optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), lr=learning_rate)
        elif optimizer_type.lower() == 'sgd':
            optimizer = optim.SGD(filter(lambda p: p.requires_grad, self.model.parameters()), lr=learning_rate, momentum=0.9)
        else:
            raise ValueError(f"Unsupported optimizer: {optimizer_type}")
        
        scheduler = optim.lr_scheduler.StepLR(optimizer, step_size=5, gamma=0.1)
        
        best_val_acc = 0.0
        
        for epoch in range(epochs):
            self.model.train()
            train_loss = 0.0
            train_correct = 0
            train_total = 0
            
            for batch_idx, (inputs, labels) in enumerate(train_loader):
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                
                optimizer.zero_grad()
                outputs = self.model(inputs)
                loss = criterion(outputs, labels)
                loss.backward()
                optimizer.step()
                
                train_loss += loss.item()
                _, predicted = outputs.max(1)
                train_total += labels.size(0)
                train_correct += predicted.eq(labels).sum().item()
                
                if (batch_idx + 1) % 10 == 0:
                    print(f'Epoch [{epoch+1}/{epochs}], Step [{batch_idx+1}/{len(train_loader)}], '
                          f'Loss: {loss.item():.4f}, Acc: {100.*train_correct/train_total:.2f}%')
            
            train_acc = 100. * train_correct / train_total
            avg_train_loss = train_loss / len(train_loader)
            
            print(f'\nEpoch {epoch+1}/{epochs} - Train Loss: {avg_train_loss:.4f}, Train Acc: {train_acc:.2f}%')
            
            if val_loader:
                val_acc, val_loss = self.evaluate(val_loader)
                print(f'Validation Loss: {val_loss:.4f}, Validation Acc: {val_acc:.2f}%')
                
                if val_acc > best_val_acc:
                    best_val_acc = val_acc
                    self.save_model(save_path)
                    print(f'Best model saved to {save_path}')
            else:
                self.save_model(save_path)
            
            scheduler.step()
            print('-' * 80)
        
        print(f'Training completed. Best validation accuracy: {best_val_acc:.2f}%')
    
    def evaluate(self, data_loader: DataLoader) -> Tuple[float, float]:
        self.model.eval()
        criterion = nn.CrossEntropyLoss()
        
        total_loss = 0.0
        correct = 0
        total = 0
        
        with torch.no_grad():
            for inputs, labels in data_loader:
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                outputs = self.model(inputs)
                loss = criterion(outputs, labels)
                
                total_loss += loss.item()
                _, predicted = outputs.max(1)
                total += labels.size(0)
                correct += predicted.eq(labels).sum().item()
        
        accuracy = 100. * correct / total
        avg_loss = total_loss / len(data_loader)
        
        return accuracy, avg_loss
    
    def save_model(self, path: str):
        checkpoint = {
            'model_state_dict': self.model.state_dict(),
            'num_classes': self.num_classes,
        }
        torch.save(checkpoint, path)
        print(f'Model saved to {path}')
    
    def load_model(self, path: str):
        checkpoint = torch.load(path, map_location=self.device)
        self.model.load_state_dict(checkpoint['model_state_dict'])
        print(f'Model loaded from {path}')


def create_transforms(input_size: int = 224, augment: bool = True):
    if augment:
        transform = transforms.Compose([
            transforms.Resize((input_size, input_size)),
            transforms.RandomHorizontalFlip(),
            transforms.RandomRotation(10),
            transforms.ColorJitter(brightness=0.2, contrast=0.2, saturation=0.2),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
    else:
        transform = transforms.Compose([
            transforms.Resize((input_size, input_size)),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
    
    return transform


def main():
    NUM_CLASSES = 10
    BATCH_SIZE = 32
    EPOCHS = 10
    LEARNING_RATE = 0.001
    
    pipeline = TransferLearningPipeline(num_classes=NUM_CLASSES)
    
    pipeline.load_pretrained_model(model_name='resnet50')
    
    train_transform = create_transforms(input_size=224, augment=True)
    val_transform = create_transforms(input_size=224, augment=False)
    
    train_images = [f'path/to/train/image_{i}.jpg' for i in range(100)]
    train_labels = [i % NUM_CLASSES for i in range(100)]
    val_images = [f'path/to/val/image_{i}.jpg' for i in range(20)]
    val_labels = [i % NUM_CLASSES for i in range(20)]
    
    train_dataset = CustomDataset(train_images, train_labels, transform=train_transform)
    val_dataset = CustomDataset(val_images, val_labels, transform=val_transform)
    
    train_loader = DataLoader(train_dataset, batch_size=BATCH_SIZE, shuffle=True, num_workers=4)
    val_loader = DataLoader(val_dataset, batch_size=BATCH_SIZE, shuffle=False, num_workers=4)
    
    pipeline.fine_tune(
        train_loader=train_loader,
        val_loader=val_loader,
        epochs=EPOCHS,
        learning_rate=LEARNING_RATE,
        optimizer_type='adam',
        save_path='finetuned_resnet50.pth',
        freeze_backbone=True
    )
    
    test_acc, test_loss = pipeline.evaluate(val_loader)
    print(f'Final Test Accuracy: {test_acc:.2f}%, Test Loss: {test_loss:.4f}')


if __name__ == '__main__':
    main()